import React, { useEffect, useState } from "react";
import Navbar from "../../components/Navbar";
import api from "../../api/axiosInstance";
import styles from "./AdminPages.module.css";

const ManagePackagesPage = () => {
  const [packages, setPackages] = useState([]);
  const [destinations, setDestinations] = useState([]);

  const [formData, setFormData] = useState({
    name: "",
    destination: "",
    duration: "",
    price: "",
    image: "", // (kept but NOT sent)
    description: "",
    transportation: "",
    sightseeing: "",
    meals: "",
    itinerary: "",
  });

  const [hotels, setHotels] = useState([
    { name: "", pricePerDay: "", description: "", image: "" }, // image not sent
  ]);

  useEffect(() => {
    loadPackages();
    loadDestinations();
  }, []);

  const loadPackages = async () => {
    const res = await api.get("/packages");
    setPackages(res.data.data);
  };

  const loadDestinations = async () => {
    const res = await api.get("/destinations");
    setDestinations(res.data.data);
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // PACKAGE IMAGE (still stored locally but NOT sent)
  const handlePackageImage = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onloadend = () => {
      setFormData((prev) => ({
        ...prev,
        image: reader.result,
      }));
    };

    reader.readAsDataURL(file);
  };

  // ADD HOTEL
  const addHotel = () => {
    setHotels([
      ...hotels,
      { name: "", pricePerDay: "", description: "", image: "" },
    ]);
  };

  // HOTEL INPUT CHANGE
  const handleHotelChange = (index, e) => {
    const updated = [...hotels];
    updated[index][e.target.name] = e.target.value;
    setHotels(updated);
  };

  // HOTEL IMAGE (stored but NOT sent)
  const handleImageUpload = (index, e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onloadend = () => {
      const updated = [...hotels];
      updated[index].image = reader.result;
      setHotels(updated);
    };

    reader.readAsDataURL(file);
  };

  // 🚀 FIXED SUBMIT (NO IMAGE SENT)
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const cleanedHotels = hotels.map((h) => ({
        name: h.name,
        pricePerDay: Number(h.pricePerDay),
        description: h.description,
      }));

      const payload = {
        name: formData.name,
        destination: formData.destination,
        duration: formData.duration,
        price: Number(formData.price),

        description: formData.description,

        transportation: formData.transportation
          ? formData.transportation.split(",")
          : [],

        sightseeing: formData.sightseeing
          ? formData.sightseeing.split(",")
          : [],

        meals: formData.meals
          ? formData.meals.split(",")
          : [],

        itinerary: formData.itinerary
          ? formData.itinerary.split(",")
          : [],

        hotels: cleanedHotels,
      };

      console.log("FINAL PAYLOAD:", payload);

      await api.post("/packages", payload);

      alert("✅ Package Added!");

      // RESET FORM
      setFormData({
        name: "",
        destination: "",
        duration: "",
        price: "",
        image: "",
        description: "",
        transportation: "",
        sightseeing: "",
        meals: "",
        itinerary: "",
      });

      setHotels([
        { name: "", pricePerDay: "", description: "", image: "" },
      ]);

      loadPackages();
    } catch (err) {
      console.error("ERROR:", err.response?.data || err);
      alert("❌ Failed to add package");
    }
  };

  return (
    <>
      <Navbar />

      <div className={styles.container}>
        <h1 className={styles.heading}>✈️ Manage Packages</h1>

        {/* FORM */}
        <form onSubmit={handleSubmit}>
          <div className={styles.layout}>

            {/* LEFT */}
            <div className={styles.left}>
              <input name="name" placeholder="Package Name" value={formData.name} onChange={handleChange} />

              <select name="destination" value={formData.destination} onChange={handleChange}>
                <option value="">Select Destination</option>
                {destinations.map((d) => (
                  <option key={d._id} value={d._id}>{d.name}</option>
                ))}
              </select>

              <input name="duration" placeholder="Duration (4N/5D)" value={formData.duration} onChange={handleChange} />
              <input name="price" type="number" placeholder="Price" value={formData.price} onChange={handleChange} />

              {/* IMAGE (still selectable, not sent) */}
              <input type="file" accept="image/*" onChange={handlePackageImage} />

              <textarea name="description" placeholder="Description" value={formData.description} onChange={handleChange} />

              <textarea name="transportation" placeholder="Transportation (comma separated)" value={formData.transportation} onChange={handleChange} />
              <textarea name="sightseeing" placeholder="Sightseeing (comma separated)" value={formData.sightseeing} onChange={handleChange} />
              <textarea name="meals" placeholder="Meals (comma separated)" value={formData.meals} onChange={handleChange} />
              <textarea name="itinerary" placeholder="Itinerary (comma separated)" value={formData.itinerary} onChange={handleChange} />

              <button className={styles.submitBtn}>Add Package</button>
            </div>

            {/* RIGHT - HOTELS */}
            <div className={styles.right}>
              <h3>🏨 Add Hotels</h3>

              {hotels.map((hotel, index) => (
                <div key={index} className={styles.hotelCard}>
                  <input name="name" placeholder="Hotel Name" value={hotel.name} onChange={(e) => handleHotelChange(index, e)} />
                  <input name="pricePerDay" type="number" placeholder="Price per day" value={hotel.pricePerDay} onChange={(e) => handleHotelChange(index, e)} />

                  <input type="file" accept="image/*" onChange={(e) => handleImageUpload(index, e)} />

                  <textarea name="description" placeholder="Hotel Description" value={hotel.description} onChange={(e) => handleHotelChange(index, e)} />
                </div>
              ))}

              <button type="button" onClick={addHotel} className={styles.addHotelBtn}>
                ➕ Add Another Hotel
              </button>
            </div>

          </div>
        </form>

        {/* TABLE */}
        <div className={styles.tableSection}>
          <h2>📦 Package History</h2>

          <table className={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
                <th>Hotels</th>
              </tr>
            </thead>

            <tbody>
              {packages.map((pkg) => (
                <tr key={pkg._id}>
                  <td>{pkg.name}</td>
                  <td>{pkg.destination?.name || "—"}</td>
                  <td>{pkg.duration}</td>
                  <td>₹{pkg.price}</td>
                  <td>{pkg.hotels?.length || 0}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </>
  );
};

export default ManagePackagesPage;
